// api/fill-permit-pdf.js
// Fills official jurisdiction permit PDFs with Parcoria form data
// Jurisdiction is determined automatically from the form's jurisdiction field
// Adding a new city: convert PDF to base64, add to EMBEDDED_PDFS, add to JURISDICTION_CONFIG

import { PDFDocument } from 'pdf-lib'

// ─── Embedded PDFs (base64) ──────────────────────────────────────────────────
// Embedded directly so Vercel serverless functions can access them without filesystem reads
// To add a new city: python3 -c "import base64; print(base64.b64encode(open('form.pdf','rb').read()).decode())"

const EMBEDDED_PDFS = {
  'durham-building-permit.pdf': '',
  // 'chapel-hill-building-permit.pdf': '<base64 string here>',
  // 'raleigh-building-permit.pdf': '<base64 string here>',
}

// ─── Jurisdiction config ─────────────────────────────────────────────────────
// status: 'active' = fillable PDF available | 'coming_soon' = falls back to jsPDF

const JURISDICTION_CONFIG = {

  durham: {
    status: 'active',
    label: 'Durham',
    building: {
      pdf: 'durham-building-permit.pdf',
      rev: 'Doc.983 Rev.08.01.2025',
      fieldMap: {
        'JOB ADDRESS':                  'jobAddress',
        'LOTUNIT':                      'lotUnit',
        'SUBDIVISION':                  'subdivision',
        'JOB DESCRIPTION Must align with the checklist construction plan and site plan where required': 'jobDescription',
        'CONTRACTOR':                   'contractorName',
        'STATE CONTRACTOR LICENSE NO':  'contractorLicense',
        'EMAIL FOR POINTOFCONTACT':     'contractorEmail',
        'PHONE':                        'contractorPhone',
        'REQUIRED DURHAM CONTRACTOR ID CID': 'durhamCID',
        'ADDRESS':                      'contractorAddress',
        'CITY':                         'contractorCity',
        'STATE':                        'contractorState',
        'ZIP CODE':                     'contractorZip',
        'ARCHITECT':                    'architectName',
        'EMAIL':                        'architectEmail',
        'PHONE_2':                      'architectPhone',
        'ADDRESS_2':                    'architectAddress',
        'CITY_2':                       'architectCity',
        'STATE_2':                      'architectState',
        'ZIP CODE_2':                   'architectZip',
        'PROPERTY OWNER NAME':          'ownerName',
        'EMAIL_2':                      'ownerEmail',
        'PHONE_3':                      'ownerPhone',
        'undefined':                    'building',
        'undefined2':                   'electrical',
        'undefined3':                   'plumbing',
        'undefined4':                   'mechanical',
        'undefined5':                   'fire',
        'TOTAL PROJECT COST':           '__totalCost',
        'PRINT NAME':                   'signerName',
        'DATE':                         'signDate',
      },
      tradeCheckboxes: [
        { yes: 'Check Box1.0.0', no: 'Check Box1.0.1', key: 'hasElectrical', default: true },
        { yes: 'Check Box1.1.0', no: 'Check Box1.1.1', key: 'hasPlumbing',   default: true },
        { yes: 'Check Box1.2.0', no: 'Check Box1.2.1', key: 'hasMechanical', default: true },
        { yes: 'Check Box1.3.0', no: 'Check Box1.3.1', key: 'hasFire',       default: false },
      ],
      questionCheckboxes: [
        { yes: 'Check Box2.0.0', no: 'Check Box2.0.1', key: 'landDisturbance' },
        { yes: 'Check Box2.1.0', no: 'Check Box2.1.1', key: 'publicFood' },
        { yes: 'Check Box2.2.0', no: 'Check Box2.2.1', key: 'sprinkler' },
        { yes: 'Check Box2.3.0', no: 'Check Box2.3.1', key: 'subSlab' },
        { yes: 'Check Box2.4.0', no: 'Check Box2.4.1', key: 'wellSeptic' },
        { yes: 'Check Box2.5.0', no: 'Check Box2.5.1', key: 'drainage' },
      ],
    },
  },

  raleigh:      { status: 'coming_soon', label: 'Raleigh' },
  chapelhill:   { status: 'coming_soon', label: 'Chapel Hill' },
  cary:         { status: 'coming_soon', label: 'Cary' },
  apex:         { status: 'coming_soon', label: 'Apex' },
  hollysprings: { status: 'coming_soon', label: 'Holly Springs' },
  wakeforest:   { status: 'coming_soon', label: 'Wake Forest' },
  morrisville:  { status: 'coming_soon', label: 'Morrisville' },
  garner:       { status: 'coming_soon', label: 'Garner' },
  fuquayvarina: { status: 'coming_soon', label: 'Fuquay-Varina' },
}

// ─── Fill logic ───────────────────────────────────────────────────────────────

async function fillJurisdictionPDF(permitTypeConfig, form, totalCost) {
  const b64 = EMBEDDED_PDFS[permitTypeConfig.pdf]
  if (!b64) throw new Error('PDF not embedded: ' + permitTypeConfig.pdf)

  const pdfBytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0))
  const pdfDoc = await PDFDocument.load(pdfBytes)
  const pdfForm = pdfDoc.getForm()

  // Text fields
  for (const [fieldName, formKey] of Object.entries(permitTypeConfig.fieldMap)) {
    try {
      const textField = pdfForm.getTextField(fieldName)
      let value = ''
      if (formKey === '__totalCost') {
        value = '$' + (totalCost || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })
      } else {
        value = String(form[formKey] || '')
      }
      textField.setText(value)
    } catch {}
  }

  // Trade work checkboxes
  for (const cb of (permitTypeConfig.tradeCheckboxes || [])) {
    const checked = form[cb.key] !== undefined ? form[cb.key] : cb.default
    try {
      if (checked) pdfForm.getCheckBox(cb.yes).check()
      else pdfForm.getCheckBox(cb.no).check()
    } catch {}
  }

  // Required question checkboxes
  for (const cb of (permitTypeConfig.questionCheckboxes || [])) {
    try {
      if (form[cb.key]) pdfForm.getCheckBox(cb.yes).check()
      else pdfForm.getCheckBox(cb.no).check()
    } catch {}
  }

  return pdfDoc.save()
}

// ─── Handler ─────────────────────────────────────────────────────────────────

export default async function handler(req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*')
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS')
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type')
  if (req.method === 'OPTIONS') return res.status(200).end()
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' })

  let body = req.body
  if (typeof body === 'string') {
    try { body = JSON.parse(body) } catch { body = {} }
  }

  const { form, permitType = 'building', totalCost = 0 } = body || {}
  if (!form) return res.status(400).json({ error: 'Form data required' })

  const jurisdiction = (form.jurisdiction || 'durham').toLowerCase()
  const jurConfig = JURISDICTION_CONFIG[jurisdiction]

  if (!jurConfig) {
    return res.status(400).json({ error: 'unsupported_jurisdiction', message: jurisdiction + ' not supported.' })
  }

  if (jurConfig.status === 'coming_soon') {
    return res.status(400).json({ error: 'coming_soon', label: jurConfig.label, message: jurConfig.label + ' permit PDF coming soon.' })
  }

  const permitTypeConfig = jurConfig[permitType]
  if (!permitTypeConfig) {
    return res.status(400).json({ error: 'unsupported_permit_type', message: permitType + ' not available for ' + jurConfig.label })
  }

  try {
    const filledBytes = await fillJurisdictionPDF(permitTypeConfig, form, totalCost)
    const address = (form.jobAddress || jurisdiction).replace(/[^a-z0-9]/gi, '-').toLowerCase().slice(0, 30)
    const filename = jurisdiction + '-' + permitType + '-permit-' + address + '.pdf'

    res.setHeader('Content-Type', 'application/pdf')
    res.setHeader('Content-Disposition', 'attachment; filename="' + filename + '"')
    res.setHeader('Content-Length', filledBytes.length)
    return res.send(Buffer.from(filledBytes))
  } catch (err) {
    console.error('PDF fill error:', err.message)
    return res.status(500).json({ error: err.message })
  }
}
